  await expect(results).toHaveCount(5, { timeout: 5000 })

  // 點擊第一個結果
  await results.first().click()

  // 驗證市場頁面已載入
  await expect(page).toHaveURL(/\/markets\//)
  await expect(page.locator('h1')).toBeVisible()
})
```

